import os
import pickle
import hashlib
import secrets
from pathlib import Path
from typing import Any, Dict, Optional
from flask import Flask, request, jsonify, abort
from werkzeug.utils import secure_filename
import logging

app = Flask(__name__)

# Security configuration
ALLOWED_EXTENSIONS = {'pkl', 'pickle'}
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10MB
MODEL_STORAGE_DIR = Path("./models")
MODEL_STORAGE_DIR.mkdir(exist_ok=True)

# Secure model loading
def load_model_secure(file_path: Path) -> Any:
    """Safely load a pickled model with security checks."""
    try:
        # Verify file exists and is within allowed directory
        if not file_path.exists():
            raise ValueError("Model file not found")
        
        if not str(file_path.resolve()).startswith(str(MODEL_STORAGE_DIR.resolve())):
            raise ValueError("Invalid file path")
        
        # Check file size
        if file_path.stat().st_size > MAX_FILE_SIZE:
            raise ValueError("Model file too large")
        
        # Load with restricted pickle
        with open(file_path, 'rb') as f:
            # Use pickle.loads with restricted protocol
            model = pickle.load(f)
        
        return model
    except Exception as e:
        logging.error(f"Failed to load model: {e}")
        raise ValueError("Invalid model file")

# Secure file upload
def save_uploaded_model(file) -> str:
    """Save uploaded model file securely."""
    if not file or file.filename == '':
        raise ValueError("No file selected")
    
    filename = secure_filename(file.filename)
    if not filename:
        raise ValueError("Invalid filename")
    
    # Validate extension
    if not filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS:
        raise ValueError("Invalid file type")
    
    # Generate secure unique filename
    unique_id = secrets.token_urlsafe(16)
    safe_filename = f"{unique_id}_{filename}"
    file_path = MODEL_STORAGE_DIR / safe_filename
    
    # Save file
    file.save(str(file_path))
    
    return safe_filename

@app.route('/upload', methods=['POST'])
def upload_model():
    """Upload a model for inference."""
    try:
        if 'model' not in request.files:
            return jsonify({"error": "No model file provided"}), 400
        
        file = request.files['model']
        model_name = save_uploaded_model(file)
        
        # Verify model can be loaded
        model_path = MODEL_STORAGE_DIR / model_name
        model = load_model_secure(model_path)
        
        return jsonify({
            "message": "Model uploaded successfully",
            "model_name": model_name
        }), 201
        
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logging.error(f"Upload error: {e}")
        return jsonify({"error": "Internal server error"}), 500

@app.route('/predict/<model_name>', methods=['POST'])
def predict(model_name: str):
    """Perform inference using uploaded model."""
    try:
        # Validate model name
        if not model_name:
            return jsonify({"error": "Model name required"}), 400
        
        # Construct path
        model_path = MODEL_STORAGE_DIR / model_name
        
        # Load model securely
        model = load_model_secure(model_path)
        
        # Get input data
        if not request.is_json:
            return jsonify({"error": "Content-Type must be application/json"}), 400
        
        data = request.get_json()
        if not data:
            return jsonify({"error": "No input data provided"}), 400
        
        # Perform prediction
        if hasattr(model, 'predict'):
            prediction = model.predict(data)
        elif hasattr(model, 'predict_proba'):
            prediction = model.predict_proba(data)
        else:
            return jsonify({"error": "Model does not support prediction"}), 400
        
        return jsonify({"prediction": prediction.tolist() if hasattr(prediction, 'tolist') else prediction}), 200
        
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logging.error(f"Prediction error: {e}")
        return jsonify({"error": "Internal server error"}), 500

